module alu(alu_A, B, CTRL, RESULT);
input [31:0] alu_A, B;
input [1:0] CTRL;
output reg [31:0] RESULT;

always @(*) begin
    case (CTRL)
        2'b00: RESULT = alu_A + B;
        2'b01: RESULT = alu_A - B;
        2'b10: RESULT = alu_A & B;
        2'b11: RESULT = alu_A | B;
        default: RESULT = 0;
    endcase
end

endmodule
